CREATE PROCEDURE test_xslt_fuzz () {
  DECLARE result VARCHAR;
  DECLARE sheet_name VARCHAR := 'my_stylesheet.xsl';
  DECLARE xml_string VARCHAR := '<root><case>1</case></root>';
  xslt_sheet (sheet_name, xml_tree_doc (xml_tree (file_to_string (sheet_name))));
  result := xslt (sheet_name, xml_tree_doc (xml_tree (xml_string)));
  SELECT result OR NULL FROM dual;
};
